using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ────────────────────────────────────────────────────────────

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
if (string.IsNullOrEmpty(apiKey))
{
    Console.Error.WriteLine("Error: set the OPENAI_API_KEY environment variable.");
    Console.Error.WriteLine("  export OPENAI_API_KEY=sk-...");
    return 1;
}

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ── Build the AI agent ───────────────────────────────────────────────────────

IChatClient innerClient = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient();

var researchTools = new ResearchTools();

var agent = new ChatClientAgent(
    innerClient,
    instructions: """
        You are a thorough research agent. When given a topic:
        1. Search the web with multiple, varied queries to gather broad information.
        2. Save each key finding as a note with a descriptive title.
        3. After at least 2-3 searches, retrieve your notes and produce a
           well-structured summary that covers the most important points.
        Be factual, cite sources by URL, and organise information clearly.
        """,
    name: "ResearchAgent",
    description: "AI agent that researches topics via web search and note-taking",
    tools:
    [
        AIFunctionFactory.Create(researchTools.SearchWeb),
        AIFunctionFactory.Create(researchTools.SaveNote),
        AIFunctionFactory.Create(researchTools.GetNotes),
    ]);

// ── Interactive loop ─────────────────────────────────────────────────────────

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 AI Research Agent           ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or       ║");
Console.WriteLine("║  type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

var session = await agent.CreateSessionAsync();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var input = Console.ReadLine();
    if (string.IsNullOrWhiteSpace(input)
        || input.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Researching… (the agent will search the web and take notes)");
    Console.ResetColor();

    try
    {
        var response = await agent.RunAsync(
            $"Research this topic thoroughly: {input}",
            session,
            options: null,
            cancellationToken: CancellationToken.None);

        Console.WriteLine();
        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("═══ Research Summary ═══");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }
}

Console.WriteLine("Goodbye!");
return 0;

// ── Tool implementations ─────────────────────────────────────────────────────

/// <summary>
/// Provides the web-search and note-taking tools that the research agent can invoke.
/// </summary>
sealed class ResearchTools
{
    private readonly List<(string Title, string Content)> _notes = [];
    private readonly HttpClient _http = new();

    public ResearchTools()
    {
        _http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
    }

    // ── Web search ───────────────────────────────────────────────────────────

    [Description("Search the web for information on a query. Returns titles, URLs, and snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up")] string query,
        [Description("Maximum number of results to return (1-5)")] int maxResults = 3)
    {
        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";

        try
        {
            var html = await _http.GetStringAsync(url);
            var results = ParseSearchResults(html, Math.Clamp(maxResults, 1, 5));

            if (results.Count == 0)
                return $"No results found for: {query}";

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for \"{query}\":\n");
            foreach (var (i, r) in results.Select((r, i) => (i, r)))
            {
                sb.AppendLine($"{i + 1}. {r.Title}");
                sb.AppendLine($"   URL: {r.Url}");
                sb.AppendLine($"   {r.Snippet}\n");
            }
            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    // ── Note-taking ──────────────────────────────────────────────────────────

    [Description("Save a research note with a title and content. Use this to record key findings.")]
    public string SaveNote(
        [Description("Short descriptive title for the note")] string title,
        [Description("The content or findings to record")] string content)
    {
        _notes.Add((title, content));
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieve all saved research notes. Use before writing a final summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"Research Notes ({_notes.Count} total):\n");
        foreach (var (i, n) in _notes.Select((n, i) => (i, n)))
        {
            sb.AppendLine($"--- Note #{i + 1}: {n.Title} ---");
            sb.AppendLine($"{n.Content}\n");
        }
        return sb.ToString();
    }

    // ── HTML parsing helpers ─────────────────────────────────────────────────

    private static List<(string Title, string Url, string Snippet)> ParseSearchResults(
        string html, int max)
    {
        var results = new List<(string, string, string)>();

        var linkRx = new Regex(
            @"<a[^>]+class=""result__a""[^>]*href=""([^""]*?)""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);
        var snippetRx = new Regex(
            @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);

        var links = linkRx.Matches(html);
        var snippets = snippetRx.Matches(html);

        for (int i = 0; i < Math.Min(links.Count, max); i++)
        {
            var title = StripHtml(links[i].Groups[2].Value);
            var rawUrl = links[i].Groups[1].Value;

            // Decode DuckDuckGo redirect URLs
            if (rawUrl.Contains("uddg="))
            {
                var m = Regex.Match(rawUrl, @"uddg=([^&]+)");
                if (m.Success)
                    rawUrl = WebUtility.UrlDecode(m.Groups[1].Value);
            }

            var snippet = i < snippets.Count
                ? StripHtml(snippets[i].Groups[1].Value)
                : "";

            if (!string.IsNullOrWhiteSpace(title))
                results.Add((title, rawUrl, snippet));
        }

        return results;
    }

    private static string StripHtml(string html) =>
        WebUtility.HtmlDecode(Regex.Replace(html, "<[^>]+>", "").Trim());
}

