             return "No notes saved yet.";

         var sb = new StringBuilder();
         sb.AppendLine($"Research Notes ({_notes.Count} total):\n");
         foreach (var (i, n) in _notes.Select((n, i) => (i, n)))
         {
             sb.AppendLine($"--- Note #{i + 1}: {n.Title} ---");
             sb.AppendLine($"{n.Content}\n");
         }
         return sb.ToString();
     }

     // ── HTML parsing helpers ─────────────────────────────────────────────────

     private static List<(string Title, string Url, string Snippet)> ParseSearchResults(
         string html, int max)
     {
         var results = new List<(string, string, string)>();

         var linkRx = new Regex(
             @"<a[^>]+class=""result__a""[^>]*href=""([^""]*?)""[^>]*>(.*?)</a>",
             RegexOptions.Singleline);
         var snippetRx = new Regex(
             @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
             RegexOptions.Singleline);

         var links = linkRx.Matches(html);
         var snippets = snippetRx.Matches(html);

         for (int i = 0; i < Math.Min(links.Count, max); i++)
         {
             var title = StripHtml(links[i].Groups[2].Value);
             var rawUrl = links[i].Groups[1].Value;

             // Decode DuckDuckGo redirect URLs
             if (rawUrl.Contains("uddg="))
             {
                 var m = Regex.Match(rawUrl, @"uddg=([^&]+)");
                 if (m.Success)
                     rawUrl = WebUtility.UrlDecode(m.Groups[1].Value);
             }

             var snippet = i < snippets.Count
                 ? StripHtml(snippets[i].Groups[1].Value)
                 : "";

             if (!string.IsNullOrWhiteSpace(title))
                 results.Add((title, rawUrl, snippet));
         }

         return results;
     }

     private static string StripHtml(string html) =>
         WebUtility.HtmlDecode(Regex.Replace(html, "<[^>]+>", "").Trim());
 }
